#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> nums;
    nums.reserve(n);
    for (int i = 0; i < n; ++i)
    {
        int x{};
        std::cin >> x;
        nums.push_back(x);
    }

    for (int i = n - 1; i >= 0; --i)
        std::cout << nums[i] << '\n';

    return 0;
}

