solution_code:
#include <iostream>
#include <iomanip>
#include <vector>

double cappedAverage(const std::vector<int>& data, int cap)
{
    std::vector<int> copy = data;
    int newSize = (cap < (int)copy.size()) ? cap : (int)copy.size();
    copy.resize(newSize);

    double sum = 0.0;
    for (int i = 0; i < (int)copy.size(); ++i)
        sum += copy[i];

    return sum / (double)copy.size();
}

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> nums;
    for (int i = 0; i < n; ++i)
    {
        int x{};
        std::cin >> x;
        nums.push_back(x);
    }

    int cap{};
    std::cin >> cap;

    double avg = cappedAverage(nums, cap);
    std::cout << std::fixed << std::setprecision(2) << "Average: " << avg << '\n';

    return 0;
}
